"use client";

import * as React from "react";
import {
  Alert,
  AlertDescription,
  AlertTitle,
  AmountBreakdown,
  Badge,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  Container,
  HStack,
  MetadataList,
  NumberInput,
  RadioGroup,
  RadioGroupItem,
  RouteStops,
  Select,
  Separator,
  Stepper,
  ToggleGroup,
  ToggleGroupItem,
  VStack,
  formatCurrency,
} from "@gunjo/ui";
import type { StepperStep, RouteStopItem } from "@gunjo/ui";
import { SeatMap } from "./SeatMap";
import {
  type Passengers,
  type SeatClass,
  type TrainOption,
  type TripType,
  type Vacancy,
  SEAT_CLASS_LABEL,
  STATIONS,
  TRAINS,
  TRAIN_ROUTES,
  VACANCY_LABEL,
  VACANCY_MARK,
  carsForTrain,
  computeFare,
} from "./data";

// ---------------------------------------------------------------------------
// 予約ステップ
// ---------------------------------------------------------------------------
type StepKey = "train" | "seat" | "passenger" | "review" | "payment";

const STEP_ORDER: StepKey[] = ["train", "seat", "passenger", "review", "payment"];
const STEP_LABEL: Record<StepKey, string> = {
  train: "列車選択",
  seat: "座席選択",
  passenger: "人数・券種",
  review: "内容確認",
  payment: "決済",
};

const VACANCY_BADGE: Record<Vacancy, "success" | "warning" | "destructive"> = {
  available: "success",
  few: "warning",
  full: "destructive",
};

function minutesToText(min: number): string {
  const h = Math.floor(min / 60);
  const m = min % 60;
  return h > 0 ? `${h}時間${m}分` : `${m}分`;
}

export default function ExpressReservationPage() {
  // 検索条件
  const [from, setFrom] = React.useState("東京");
  const [to, setTo] = React.useState("新大阪");
  const [date, setDate] = React.useState("2026-07-10");
  const [depFrom, setDepFrom] = React.useState("09:00");

  // 人数・券種
  const [passengers, setPassengers] = React.useState<Passengers>({
    adult: 1,
    child: 0,
  });
  const [trip, setTrip] = React.useState<TripType>("oneway");
  const [seatClass, setSeatClass] = React.useState<SeatClass>("reserved");

  // 選択状態
  const [step, setStep] = React.useState<StepKey>("train");
  const [trainId, setTrainId] = React.useState<string | null>(null);
  const [carIndex, setCarIndex] = React.useState(0);
  const [selectedSeats, setSelectedSeats] = React.useState<string[]>([]);
  const [paid, setPaid] = React.useState(false);

  const totalPax = passengers.adult + passengers.child;
  const train = TRAINS.find((t) => t.id === trainId) ?? null;
  const cars = React.useMemo(() => carsForTrain(seatClass), [seatClass]);
  const car = cars[Math.min(carIndex, cars.length - 1)];

  const fare = React.useMemo(
    () => (train ? computeFare(train, seatClass, passengers, trip) : null),
    [train, seatClass, passengers, trip]
  );

  const stepperSteps: StepperStep[] = STEP_ORDER.map((key) => {
    const curIdx = STEP_ORDER.indexOf(step);
    const myIdx = STEP_ORDER.indexOf(key);
    return {
      label: STEP_LABEL[key],
      state:
        myIdx < curIdx ? "completed" : myIdx === curIdx ? "current" : "upcoming",
    };
  });

  function selectTrain(t: TrainOption) {
    setTrainId(t.id);
    setSelectedSeats([]);
    setCarIndex(0);
    // 自由席は座席選択をスキップ
    setStep(seatClass === "nonreserved" ? "passenger" : "seat");
  }

  function toggleSeat(seatId: string) {
    setSelectedSeats((prev) => {
      if (prev.includes(seatId)) return prev.filter((s) => s !== seatId);
      if (prev.length >= totalPax) {
        // 人数超過時は最後をはずして追加（直感的な振る舞い）
        return [...prev.slice(1), seatId];
      }
      return [...prev, seatId];
    });
  }

  function goNext() {
    const idx = STEP_ORDER.indexOf(step);
    if (idx < STEP_ORDER.length - 1) setStep(STEP_ORDER[idx + 1]);
  }
  function goBack() {
    const idx = STEP_ORDER.indexOf(step);
    if (idx > 0) {
      // 自由席のときは座席選択をスキップして戻る
      if (STEP_ORDER[idx - 1] === "seat" && seatClass === "nonreserved") {
        setStep("train");
      } else {
        setStep(STEP_ORDER[idx - 1]);
      }
    }
  }

  const seatsNeeded = seatClass === "nonreserved" ? 0 : totalPax;
  const seatsChosenOk =
    seatClass === "nonreserved" || selectedSeats.length === totalPax;

  return (
    <main className="min-h-screen bg-background pb-28">
      {/* ヘッダー */}
      <header className="border-b bg-card">
        <Container size="lg" className="py-3">
          <HStack justify="between" align="center">
            <div>
              <p className="text-xs text-muted-foreground">JR 新幹線・特急 オンライン予約</p>
              <h1 className="text-lg font-bold tracking-tight">特急券・指定席予約</h1>
            </div>
            <Badge variant="outline">ゲスト予約</Badge>
          </HStack>
        </Container>
      </header>

      {/* ステップインジケータ */}
      <div className="border-b bg-card">
        <Container size="lg" className="overflow-x-auto">
          <Stepper steps={stepperSteps} aria-label="予約ステップ" />
        </Container>
      </div>

      <Container size="lg" className="py-5">
        <VStack gap={5}>
          {step === "train" && (
            <TrainStep
              from={from}
              to={to}
              date={date}
              depFrom={depFrom}
              passengers={passengers}
              seatClass={seatClass}
              onFrom={setFrom}
              onTo={setTo}
              onDate={setDate}
              onDepFrom={setDepFrom}
              onSeatClass={setSeatClass}
              onSelect={selectTrain}
            />
          )}

          {step === "seat" && train && (
            <SeatStep
              train={train}
              cars={cars}
              carIndex={Math.min(carIndex, cars.length - 1)}
              onCarIndex={setCarIndex}
              selectedSeats={selectedSeats}
              maxSeats={totalPax}
              onToggleSeat={toggleSeat}
            />
          )}

          {step === "passenger" && train && (
            <PassengerStep
              passengers={passengers}
              onPassengers={setPassengers}
              trip={trip}
              onTrip={setTrip}
              seatClass={seatClass}
              selectedSeats={selectedSeats}
            />
          )}

          {step === "review" && train && fare && (
            <ReviewStep
              train={train}
              seatClass={seatClass}
              passengers={passengers}
              trip={trip}
              date={date}
              selectedSeats={selectedSeats}
              carNumber={car.number}
              fare={fare}
            />
          )}

          {step === "payment" && train && fare && (
            <PaymentStep total={fare.total} paid={paid} onPay={() => setPaid(true)} />
          )}
        </VStack>
      </Container>

      {/* スティッキー・フッター（料金＋ナビ） */}
      {train && step !== "payment" && (
        <div className="fixed inset-x-0 bottom-0 z-20 border-t bg-card/95 backdrop-blur">
          <Container size="lg" className="py-3">
            <HStack justify="between" align="center" gap={3} wrap>
              <div className="min-w-0">
                <p className="text-xs text-muted-foreground">お支払い合計（{totalPax}名）</p>
                <p className="text-xl font-bold tabular-nums">
                  {fare ? formatCurrency(fare.total) : "—"}
                </p>
              </div>
              <HStack gap={2}>
                <Button variant="outline" onClick={goBack}>
                  戻る
                </Button>
                {step === "seat" && (
                  <Button
                    onClick={goNext}
                    disabled={!seatsChosenOk}
                    aria-disabled={!seatsChosenOk}
                  >
                    {selectedSeats.length}/{seatsNeeded} 席 選択 →
                  </Button>
                )}
                {step === "passenger" && (
                  <Button onClick={goNext} disabled={totalPax < 1}>
                    内容確認へ →
                  </Button>
                )}
                {step === "review" && (
                  <Button onClick={goNext}>決済に進む →</Button>
                )}
              </HStack>
            </HStack>
          </Container>
        </div>
      )}
    </main>
  );
}

// ===========================================================================
// STEP 1 — 列車選択（検索条件 + 候補列車リスト）
// ===========================================================================
function TrainStep(props: {
  from: string;
  to: string;
  date: string;
  depFrom: string;
  passengers: Passengers;
  seatClass: SeatClass;
  onFrom: (v: string) => void;
  onTo: (v: string) => void;
  onDate: (v: string) => void;
  onDepFrom: (v: string) => void;
  onSeatClass: (v: SeatClass) => void;
  onSelect: (t: TrainOption) => void;
}) {
  const {
    from,
    to,
    date,
    depFrom,
    seatClass,
    onFrom,
    onTo,
    onDate,
    onDepFrom,
    onSeatClass,
    onSelect,
  } = props;

  return (
    <VStack gap={4}>
      <Card>
        <CardHeader className="pb-3">
          <CardTitle as="h2" className="text-base">
            検索条件
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
            <Select
              label="出発駅"
              value={from}
              onChange={(e) => onFrom(e.target.value)}
            >
              {STATIONS.map((s) => (
                <option key={s.code} value={s.name}>
                  {s.name}
                </option>
              ))}
            </Select>
            <Select
              label="到着駅"
              value={to}
              onChange={(e) => onTo(e.target.value)}
            >
              {STATIONS.map((s) => (
                <option key={s.code} value={s.name}>
                  {s.name}
                </option>
              ))}
            </Select>
            <div className="flex flex-col gap-1.5">
              <label
                htmlFor="ex-date"
                className="text-sm font-medium leading-none text-foreground"
              >
                乗車日
              </label>
              <input
                id="ex-date"
                type="date"
                value={date}
                onChange={(e) => onDate(e.target.value)}
                className="inline-flex h-9 w-full rounded-lg border border-input bg-transparent px-3 py-2 text-sm text-foreground focus:outline-none focus:ring-1 focus:ring-ring"
              />
            </div>
            <div className="flex flex-col gap-1.5">
              <label
                htmlFor="ex-time"
                className="text-sm font-medium leading-none text-foreground"
              >
                出発時刻以降
              </label>
              <input
                id="ex-time"
                type="time"
                value={depFrom}
                onChange={(e) => onDepFrom(e.target.value)}
                className="inline-flex h-9 w-full rounded-lg border border-input bg-transparent px-3 py-2 text-sm text-foreground focus:outline-none focus:ring-1 focus:ring-ring"
              />
            </div>
          </div>

          <Separator className="my-4" />

          <div className="flex flex-col gap-1.5">
            <span className="text-sm font-medium leading-none text-foreground">
              席種
            </span>
            <ToggleGroup
              type="single"
              value={seatClass}
              onValueChange={(v) => v && onSeatClass(v as SeatClass)}
              disallowEmpty
              variant="outline"
              className="justify-start"
              aria-label="席種"
            >
              <ToggleGroupItem value="reserved">指定席</ToggleGroupItem>
              <ToggleGroupItem value="green">グリーン車</ToggleGroupItem>
              <ToggleGroupItem value="nonreserved">自由席</ToggleGroupItem>
            </ToggleGroup>
          </div>
        </CardContent>
      </Card>

      <div>
        <HStack justify="between" align="baseline" className="mb-2">
          <h2 className="text-base font-semibold">
            {from} → {to}
            <span className="ml-2 text-sm font-normal text-muted-foreground">
              候補列車 {TRAINS.length}件
            </span>
          </h2>
        </HStack>

        <VStack gap={3}>
          {TRAINS.map((t) => {
            const vac = t.vacancy[seatClass];
            const fee =
              seatClass === "nonreserved" ? t.nonreservedFee : t.reservedFee;
            const soldOut = vac === "full";
            return (
              <Card
                key={t.id}
                className={soldOut ? "opacity-60" : undefined}
              >
                <CardContent className="p-4">
                  <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
                    <div className="min-w-0 flex-1">
                      <HStack gap={2} align="center" wrap className="mb-1">
                        <span className="font-semibold">{t.name}</span>
                        {t.earlyDiscount && seatClass !== "nonreserved" && (
                          <Badge variant="info">早特あり</Badge>
                        )}
                      </HStack>
                      <div className="flex items-baseline gap-2 text-lg font-bold tabular-nums">
                        <span>{t.depTime}</span>
                        <span className="text-muted-foreground" aria-hidden>
                          →
                        </span>
                        <span>{t.arrTime}</span>
                        <span className="text-xs font-normal text-muted-foreground">
                          所要 {minutesToText(t.durationMin)}・乗換{t.transfers}回
                        </span>
                      </div>
                      <p className="mt-1 text-xs text-muted-foreground">
                        {t.facilities.join("・")}
                      </p>
                    </div>

                    <div className="flex items-center justify-between gap-4 sm:flex-col sm:items-end">
                      <div className="text-right">
                        <Badge
                          variant={VACANCY_BADGE[vac]}
                          aria-label={`${SEAT_CLASS_LABEL[seatClass]} ${VACANCY_LABEL[vac]}`}
                        >
                          {SEAT_CLASS_LABEL[seatClass]} {VACANCY_MARK[vac]}{" "}
                          {VACANCY_LABEL[vac]}
                        </Badge>
                        <p className="mt-1 text-xs text-muted-foreground tabular-nums">
                          運賃 {formatCurrency(t.fare)} ＋ 特急{" "}
                          {formatCurrency(fee)}〜
                        </p>
                      </div>
                      <Button
                        size="sm"
                        onClick={() => onSelect(t)}
                        disabled={soldOut}
                        aria-label={`${t.name} を選択`}
                      >
                        {soldOut ? "満席" : "選択 →"}
                      </Button>
                    </div>
                  </div>
                </CardContent>
              </Card>
            );
          })}
        </VStack>
      </div>
    </VStack>
  );
}

// ===========================================================================
// STEP 2 — 座席選択
// ===========================================================================
function SeatStep(props: {
  train: TrainOption;
  cars: ReturnType<typeof carsForTrain>;
  carIndex: number;
  onCarIndex: (i: number) => void;
  selectedSeats: string[];
  maxSeats: number;
  onToggleSeat: (id: string) => void;
}) {
  const { train, cars, carIndex, onCarIndex, selectedSeats, maxSeats, onToggleSeat } =
    props;
  const car = cars[carIndex];

  return (
    <VStack gap={4}>
      <Card>
        <CardHeader className="pb-2">
          <CardTitle as="h2" className="text-base">
            座席を選択（{train.name}）
          </CardTitle>
        </CardHeader>
        <CardContent>
          <Alert variant="info" className="mb-4">
            <AlertTitle as="h3">
              {maxSeats}名分の座席をお選びください（残り {maxSeats - selectedSeats.length}席）
            </AlertTitle>
            <AlertDescription>
              窓側 A/E はコンセント席です。座席をタップで選択／解除できます。
            </AlertDescription>
          </Alert>

          {/* 号車選択 */}
          <div className="mb-4 flex flex-col gap-1.5">
            <span className="text-sm font-medium leading-none text-foreground">
              号車
            </span>
            <ToggleGroup
              type="single"
              value={String(car.number)}
              onValueChange={(v) => {
                if (!v) return;
                const idx = cars.findIndex((c) => String(c.number) === v);
                if (idx >= 0) onCarIndex(idx);
              }}
              disallowEmpty
              variant="outline"
              className="flex-wrap justify-start"
              aria-label="号車"
            >
              {cars.map((c) => (
                <ToggleGroupItem key={c.number} value={String(c.number)}>
                  {c.number}号車
                </ToggleGroupItem>
              ))}
            </ToggleGroup>
          </div>

          <SeatMap
            car={car}
            selectedSeatIds={selectedSeats}
            maxSeats={maxSeats}
            onToggleSeat={onToggleSeat}
          />
        </CardContent>
      </Card>

      {selectedSeats.length > 0 && (
        <Card>
          <CardContent className="p-4">
            <p className="mb-2 text-sm font-medium">選択中の座席</p>
            <HStack gap={2} wrap>
              {selectedSeats.map((s) => (
                <Badge key={s} variant="default">
                  {car.number}号車 {s}
                </Badge>
              ))}
            </HStack>
          </CardContent>
        </Card>
      )}
    </VStack>
  );
}

// ===========================================================================
// STEP 3 — 人数・券種
// ===========================================================================
function PassengerStep(props: {
  passengers: Passengers;
  onPassengers: (p: Passengers) => void;
  trip: TripType;
  onTrip: (t: TripType) => void;
  seatClass: SeatClass;
  selectedSeats: string[];
}) {
  const { passengers, onPassengers, trip, onTrip, seatClass, selectedSeats } =
    props;
  const totalPax = passengers.adult + passengers.child;
  const seatMismatch =
    seatClass !== "nonreserved" && selectedSeats.length !== totalPax;

  return (
    <VStack gap={4}>
      <Card>
        <CardHeader className="pb-2">
          <CardTitle as="h2" className="text-base">
            人数・券種
          </CardTitle>
        </CardHeader>
        <CardContent>
          <VStack gap={4}>
            <div className="grid grid-cols-2 gap-4">
              <NumberInput
                label="大人"
                description="12歳以上"
                layout="stepper"
                min={0}
                max={6}
                value={passengers.adult}
                onValueChange={(v) =>
                  onPassengers({ ...passengers, adult: v })
                }
              />
              <NumberInput
                label="小児"
                description="6〜11歳・運賃/特急料金が半額"
                layout="stepper"
                min={0}
                max={6}
                value={passengers.child}
                onValueChange={(v) =>
                  onPassengers({ ...passengers, child: v })
                }
              />
            </div>

            <Separator />

            <div className="flex flex-col gap-2">
              <span className="text-sm font-medium leading-none text-foreground">
                片道 / 往復
              </span>
              <RadioGroup
                value={trip}
                onValueChange={(v) => onTrip(v as TripType)}
                className="gap-3"
                aria-label="片道または往復"
              >
                <RadioGroupItem
                  value="oneway"
                  label="片道"
                  description="ご指定の区間を1回ご乗車"
                />
                <RadioGroupItem
                  value="round"
                  label="往復"
                  description="往復割引（運賃1割引）が適用されます"
                />
              </RadioGroup>
            </div>

            {seatMismatch && (
              <Alert variant="warning">
                <AlertTitle as="h3">座席数が人数と一致していません</AlertTitle>
                <AlertDescription>
                  {totalPax}名に対し {selectedSeats.length}席を選択中です。座席選択に戻って調整してください。
                </AlertDescription>
              </Alert>
            )}
          </VStack>
        </CardContent>
      </Card>
    </VStack>
  );
}

// ===========================================================================
// STEP 4 — 内容確認（料金内訳含む）
// ===========================================================================
function ReviewStep(props: {
  train: TrainOption;
  seatClass: SeatClass;
  passengers: Passengers;
  trip: TripType;
  date: string;
  selectedSeats: string[];
  carNumber: number;
  fare: ReturnType<typeof computeFare>;
}) {
  const {
    train,
    seatClass,
    passengers,
    trip,
    date,
    selectedSeats,
    carNumber,
    fare,
  } = props;

  const route: RouteStopItem[] = (TRAIN_ROUTES[train.id] ?? []).map(
    (s, i, arr) => ({
      id: s.id,
      title: s.name,
      status:
        i === 0 ? "completed" : i === arr.length - 1 ? "current" : "pending",
      plannedTime: s.time,
    })
  );

  const paxText = [
    passengers.adult > 0 ? `大人 ${passengers.adult}名` : null,
    passengers.child > 0 ? `小児 ${passengers.child}名` : null,
  ]
    .filter(Boolean)
    .join(" / ");

  return (
    <VStack gap={4}>
      <Card>
        <CardHeader className="pb-2">
          <CardTitle as="h2" className="text-base">
            予約内容の確認
          </CardTitle>
        </CardHeader>
        <CardContent>
          <MetadataList
            items={[
              { label: "列車", value: train.name },
              { label: "乗車日", value: date },
              {
                label: "区間",
                value: `${train.depStation} ${train.depTime} → ${train.arrStation} ${train.arrTime}`,
              },
              { label: "席種", value: SEAT_CLASS_LABEL[seatClass] },
              {
                label: "座席",
                value:
                  seatClass === "nonreserved"
                    ? "自由席（座席指定なし）"
                    : selectedSeats.length > 0
                      ? `${carNumber}号車 ${selectedSeats.join("・")}`
                      : "未選択",
              },
              { label: "人数", value: paxText || "—" },
              { label: "券種", value: trip === "round" ? "往復" : "片道" },
            ]}
          />
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="pb-2">
          <CardTitle as="h2" className="text-base">
            停車駅・行路
          </CardTitle>
        </CardHeader>
        <CardContent>
          <RouteStops
            stops={route}
            statusLabels={{
              completed: "出発",
              current: "到着",
              pending: "停車",
            }}
            timeLabels={{ planned: "時刻" }}
          />
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="pb-2">
          <CardTitle as="h2" className="text-base">
            料金の内訳
          </CardTitle>
        </CardHeader>
        <CardContent>
          <AmountBreakdown
            lines={fare.lines.map((l) => ({
              label: l.label,
              amount: l.amount,
              kind: l.kind,
              note: l.note,
            }))}
            total={{ label: "お支払い合計", amount: fare.total }}
            formula="お支払い合計 = 乗車券 ＋ 特急料金（＋グリーン料金）− 各割引"
          />
        </CardContent>
      </Card>
    </VStack>
  );
}

// ===========================================================================
// STEP 5 — 決済
// ===========================================================================
function PaymentStep(props: {
  total: number;
  paid: boolean;
  onPay: () => void;
}) {
  const { total, paid, onPay } = props;

  if (paid) {
    return (
      <Card>
        <CardContent className="p-8 text-center">
          <Badge variant="success" className="mb-3">
            予約完了
          </Badge>
          <h2 className="text-xl font-bold">ご予約ありがとうございます</h2>
