/**
 * 号車の座席表を決定論的に生成する（同じ号車なら毎回同じ配置 → ハイドレーション安全）。
 * 一部の席を予約済みにして「空席/予約済」を表現する。
 */
export function buildSeatGrid(car: CarInfo): Seat[] {
  const seats: Seat[] = [];
  for (let row = 1; row <= car.rows; row++) {
    for (const col of car.cols) {
      const isWindow = col === car.cols[0] || col === car.cols[car.cols.length - 1];
      const isMiddle = car.cols.length === 5 && col === "B";
      const position: SeatPosition = isWindow ? "window" : isMiddle ? "middle" : "aisle";
      // 決定論的な「予約済」パターン：行・列・号車から擬似乱数を作る。
      const hash = (row * 31 + col.charCodeAt(0) * 7 + car.number * 13) % 100;
      const status: SeatStatus = hash < 38 ? "occupied" : "available";
      // 窓側はコンセント席。グリーンは全席コンセント。
      const power = car.seatClass === "green" || isWindow;
      seats.push({ id: `${row}${col}`, row, col, status, position, power });
    }
  }
  return seats;
}

export const POSITION_LABEL: Record<SeatPosition, string> = {
  window: "窓側",
  aisle: "通路側",
  middle: "中央",
};

// ---------------------------------------------------------------------------
// 料金計算
// ---------------------------------------------------------------------------

export interface Passengers {
  adult: number;
  child: number;
}

export type TripType = "oneway" | "round";

export interface FareLine {
  label: string;
  amount: number;
  kind: "add" | "subtract";
  note?: string;
}

export interface FareResult {
  lines: FareLine[];
  total: number;
}

/**
 * 1区間（片道）あたりの料金内訳を計算。
 * 乗車券(運賃) ＋ 特急料金 ＋ 指定席/グリーン加算 − 割引（早特・小児・往復）= 合計
 */
export function computeFare(
  train: TrainOption,
  seatClass: SeatClass,
  passengers: Passengers,
  trip: TripType
): FareResult {
  const lines: FareLine[] = [];
  const legs = trip === "round" ? 2 : 1;
  const totalPax = passengers.adult + passengers.child;

  // 運賃（乗車券）— 小児は半額
  const fareAdult = train.fare * passengers.adult * legs;
  const fareChild = Math.floor((train.fare / 2) / 10) * 10 * passengers.child * legs;
  lines.push({
    label: "乗車券（運賃）",
    amount: fareAdult + fareChild,
    kind: "add",
    note: `${train.depStation}→${train.arrStation}${trip === "round" ? "（往復）" : "（片道）"}`,
  });

  // 特急料金
  const expressFee =
    seatClass === "nonreserved" ? train.nonreservedFee : train.reservedFee;
  // 特急料金は小児半額
  const expressAdult = expressFee * passengers.adult * legs;
  const expressChild = Math.floor((expressFee / 2) / 10) * 10 * passengers.child * legs;
  lines.push({
    label: seatClass === "nonreserved" ? "自由席特急料金" : "特急料金",
    amount: expressAdult + expressChild,
    kind: "add",
    note: `${SEAT_CLASS_LABEL[seatClass]}・通常期`,
  });

  // グリーン料金（席種加算）
  if (seatClass === "green") {
    const greenFee = SEAT_CLASS_SURCHARGE.green * totalPax * legs;
    lines.push({
      label: "グリーン料金",
      amount: greenFee,
      kind: "add",
      note: "全乗車に加算",
    });
  }

  // 早特割引（指定席系のみ）
  if (train.earlyDiscount && seatClass !== "nonreserved") {
    const disc = train.earlyDiscount * totalPax * legs;
    lines.push({
      label: "EX早特割引",
      amount: disc,
      kind: "subtract",
      note: "21日前まで",
    });
  }

  // 往復割引（運賃が片道601km以上で1割引：東京〜新大阪は対象）
  if (trip === "round") {
    const roundDisc = Math.floor((fareAdult + fareChild) * 0.1 / 10) * 10;
    lines.push({
      label: "往復割引",
      amount: roundDisc,
      kind: "subtract",
      note: "片道601km以上・運賃1割引",
    });
  }

  const total = lines.reduce(
    (sum, l) => sum + (l.kind === "subtract" ? -l.amount : l.amount),
    0
  );

  return { lines, total };
}

"use client";

import * as React from "react";
import { Badge, Button, cn } from "@gunjo/ui";
import {
  type CarInfo,
  type Seat,
  buildSeatGrid,
  POSITION_LABEL,
} from "./data";

// ---------------------------------------------------------------------------
// SeatMap — 2-D selectable seat grid.
//
// @gunjo/ui に座席表プリミティブは存在しないため完全な手組み。
// ScheduleGrid（行×列のavailabilityグリッド）は staff×日 / table×時間 用で
// 「クリックで1セルを選択トグル」する2D予約UIではない。よって自作。
// ---------------------------------------------------------------------------

export interface SeatMapProps {
  car: CarInfo;
  /** すでに選択済みの座席ID（このユーザーの選択中）。 */
  selectedSeatIds: string[];
  /** 選択できる最大席数（人数）。 */
  maxSeats: number;
  onToggleSeat: (seatId: string) => void;
}

const STATUS_LABEL: Record<string, string> = {
  available: "空席",
  occupied: "予約済",
  selected: "選択中",
};

function seatVisualState(
  seat: Seat,
  selected: boolean
): "selected" | "occupied" | "available" {
  if (selected) return "selected";
  return seat.status;
}

const SEAT_CLASSES: Record<"available" | "occupied" | "selected", string> = {
  available:
    "border-border bg-card text-foreground hover:border-primary hover:bg-primary-subtle focus-visible:ring-2 focus-visible:ring-ring",
  occupied:
    "border-border bg-muted text-muted-foreground cursor-not-allowed opacity-70",
  selected:
    "border-primary bg-primary text-primary-foreground ring-2 ring-ring ring-offset-1 ring-offset-background",
};

export function SeatMap({
  car,
  selectedSeatIds,
  maxSeats,
  onToggleSeat,
}: SeatMapProps) {
  // 号車が変わったら座席表を作り直す（決定論的なのでSSR安全）。
  const seats = React.useMemo(() => buildSeatGrid(car), [car]);
  const selected = new Set(selectedSeatIds);

  const rows = Array.from({ length: car.rows }, (_, i) => i + 1);
  const seatByPos = new Map(seats.map((s) => [s.id, s] as const));

  const grid = car.cols;
  const aisleIndex = grid.indexOf(car.aisleAfter);

  return (
    <div className="w-full">
      {/* 凡例 */}
      <div className="mb-3 flex flex-wrap items-center gap-2 text-xs">
        <span className="flex items-center gap-1.5">
          <span className="inline-block h-4 w-4 rounded border border-border bg-card" />
          空席
        </span>
        <span className="flex items-center gap-1.5">
          <span className="inline-block h-4 w-4 rounded border border-primary bg-primary" />
          選択中
        </span>
        <span className="flex items-center gap-1.5">
          <span className="inline-block h-4 w-4 rounded border border-border bg-muted" />
          予約済
        </span>
        <span className="flex items-center gap-1.5 text-muted-foreground">
          <span aria-hidden>⚡</span>
          コンセント席
        </span>
      </div>

      {/* 進行方向の目印 */}
      <div className="mb-2 flex items-center justify-center">
        <Badge variant="secondary" aria-hidden>
          ← 進行方向（{car.number}号車）
        </Badge>
      </div>

      <div
        role="grid"
        aria-label={`${car.number}号車 座席表`}
        className="mx-auto w-full max-w-md overflow-x-auto rounded-lg border bg-muted/30 p-3"
      >
        {/* 列ヘッダ */}
        <div role="row" className="flex items-center gap-1.5 pb-2">
          <span className="w-6 shrink-0" aria-hidden />
          {grid.map((col, idx) => (
            <React.Fragment key={col}>
              {idx === aisleIndex + 1 && (
                <span className="w-4 shrink-0" aria-hidden />
              )}
              <span
                role="columnheader"
                className="flex h-6 flex-1 items-center justify-center text-xs font-semibold text-muted-foreground"
              >
                {col}
              </span>
            </React.Fragment>
          ))}
        </div>

        {rows.map((row) => (
          <div key={row} role="row" className="flex items-center gap-1.5 py-0.5">
            <span
              role="rowheader"
              className="w-6 shrink-0 text-center text-xs font-medium tabular-nums text-muted-foreground"
            >
              {row}
            </span>
            {grid.map((col, idx) => {
              const seat = seatByPos.get(`${row}${col}`);
              if (!seat) return null;
              const isSelected = selected.has(seat.id);
              const vis = seatVisualState(seat, isSelected);
              const disabled =
                seat.status === "occupied" ||
                (!isSelected && selected.size >= maxSeats);
              const posLabel = POSITION_LABEL[seat.position];
              return (
                <React.Fragment key={seat.id}>
                  {idx === aisleIndex + 1 && (
                    <span
                      className="w-4 shrink-0 text-center text-[10px] text-muted-foreground"
                      aria-hidden
                    >
                      通
                    </span>
                  )}
                  <button
                    type="button"
                    role="gridcell"
                    aria-label={`${car.number}号車 ${seat.id} ${posLabel} ${
                      STATUS_LABEL[vis]
                    }${seat.power ? " コンセントあり" : ""}`}
                    aria-pressed={isSelected}
                    aria-disabled={disabled}
                    disabled={disabled && !isSelected}
                    onClick={() => !disabled && onToggleSeat(seat.id)}
                    className={cn(
                      "relative flex h-9 flex-1 items-center justify-center rounded border text-[11px] font-medium tabular-nums transition-colors focus:outline-none",
                      SEAT_CLASSES[vis]
                    )}
                  >
                    {seat.col}
                    {seat.power && (
                      <span
                        className="absolute right-0.5 top-0.5 text-[8px] leading-none"
                        aria-hidden
                      >
                        ⚡
                      </span>
                    )}
                  </button>
                </React.Fragment>
              );
            })}
          </div>
        ))}
      </div>

      {car.note && (
        <p className="mt-3 text-center text-xs text-muted-foreground">
          {car.note}・多目的室 / 多機能トイレは {car.number} 号車付近
        </p>
      )}
    </div>
  );
}
